<div class="card content-card mb-4"><div class="card-body p-4"><div class="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3"><div><h5 class="mb-1">Audit Log Explorer</h5><p class="text-muted mb-0">Review recent configuration and transactional changes recorded across the HR system.</p></div><form method="get" action="<?= e(url('/reports/audit')); ?>" class="d-flex flex-column flex-md-row gap-2"><input type="text" name="q" class="form-control" placeholder="Search module, action, actor, or IP..." value="<?= e((string) ($search ?? '')); ?>"><select name="module" class="form-select"><option value="all">All modules</option><?php foreach (($modules ?? []) as $row): ?><option value="<?= e((string) $row['module_name']); ?>" <?= (string) ($module ?? 'all') === (string) $row['module_name'] ? 'selected' : ''; ?>><?= e((string) $row['module_name']); ?></option><?php endforeach; ?></select><button type="submit" class="btn btn-outline-secondary">Filter</button></form></div></div></div>
